    k: "CREATE VOLUME main.raw.aterrizaje;\nCREATE EXTERNAL VOLUME main.raw.ext LOCATION 's3://bucket/path';\nSELECT * FROM json.`/Volumes/main/raw/aterrizaje/f.json`;",
