    k: "SELECT CAST('100$' AS INT);                      -- error\nSELECT TRY_CAST('100$' AS INT);                  -- NULL\nSELECT COALESCE(TRY_CAST('100$' AS INT), 0);     -- 0\nSELECT COALESCE(CAST('100$' AS INT), 0);         -- error: el CAST falla antes",
