    k: 'from pyspark import pipelines as dp\n\n@dp.table(comment="pedidos limpios")\n@dp.expect_or_drop("id_valido", "id IS NOT NULL")\ndef silver_pedidos():\n    return spark.readStream.table("bronze.pedidos")',
