    k: 'variables:\n  schema_name:\n    description: esquema destino\n    default: demo_schema\n\n# uso\nbase_parameters:\n  schema_name: ${var.schema_name}\n\n# en la CLI\ndatabricks bundle deploy -t dev --var="schema_name=finance_schema"',
